class Solution:
    def isSubstringPresent(self, s: str) -> bool:
        if len(s) < 2:
            return False
        seen = set()
        for a, b in zip(s, s[1:]):
            seen.add((a, b))
        for a, b in zip(reversed(s), reversed(s[:-1])):
            if (b, a) in seen:
                return True
        return False
